if ( local_rc != LDAP_SUCCESS ) {
	fprintf( stderr, "%s: could not parse entry (line=%lu)\n",
		progname, lineno );
	rc = EXIT_FAILURE;
	if( continuemode ) continue;
	break;
}

switch ( lr.lr_op ) {
case LDAP_REQ_ADD:
	request = "add";
